const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const RUNE_BLOCK_OF_3_PRICE = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

type Item = { type: string };
type QuoteStep = { type: "quote"; items: Item[] };
type Scenario = { steps: QuoteStep[] };

function calculateBasePremium(items: Item[]): number {
  const runeCount = items.filter((item) => item.type === "rune").length;
  if (runeCount === 3) {
    return RUNE_BLOCK_OF_3_PRICE;
  }
  return items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
}

export function runScenario(scenario: unknown): { results: { premium: number }[] } {
  const { steps } = scenario as Scenario;
  const items = steps[0].items;
  const basePremium = calculateBasePremium(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
  return { results: [{ premium }] };
}
